def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 3:
            for x in range(3, 0, -1):
                penalty = ((ratio - x) ** 3) / x
                priority += penalty
            priority += np.exp(ratio - 3)
        elif 1 < ratio <= 3:
            for m in range(1, int(np.ceil(ratio)) + 1):
                priority += (ratio - m) * np.sin(ratio * m)
            priority += np.log(ratio) * 5
        elif 0.7 <= ratio <= 1:
            priority = -np.log(ratio) * 3 + np.tanh(5 * (1 - ratio))
        elif 0.3 <= ratio < 0.7:
            s = 0
            for n in range(1, 5):
                s += ((0.7 - ratio) ** n) / n
            if ratio < 0.5:
                priority = s + np.sqrt(1 / (bin_cap + 1)) * 2
            else:
                priority = s + np.cos(10 * ratio)
        else:
            priority = 1 / (bin_cap + 1) + np.sum([((0.3 - ratio) ** k) / (k * 2) for k in range(1, 6)])
            if item % 2 == 0:
                priority *= 1.5
            else:
                priority /= 1.5
        if bin_cap < item * 0.5:
            priority += np.log1p(item * bin_cap) * 2
        elif bin_cap > item * 2:
            priority -= np.exp(-ratio)
        priorities[i] = priority
    return priorities
